 34	  const [isOpenSelectType, setIsOpenSelectType] = useState<boolean>(false);
 35	  const [isOpenSendKey, setIsOpenSendKey] = useState<boolean>(false);
 36	  const [status, setStatus] = useState<string>();
 37	
 38	  useEffect(() => {
 39	    const statusCallback = () => setStatus(connected);
 40	    rfb?.addEventListener('connect', statusCallback);
 41	
 42	    () => rfb?.removeEventListener('connect', statusCallback);
 43	  }, [rfb]);
 44	
 45	  const customButtons = [
 46	    {
 47	      onClick: () => rfb?.sendCtrlAltDel(),
 48	      text: 'Ctrl + Alt + Delete',
 49	    },
 50	    {
 51	      onClick: () => rfb?.sendCtrlAlt1(),
 52	      text: 'Ctrl + Alt + 1',
 53	    },
 54	    {
 55	      onClick: () => rfb?.sendCtrlAlt2(),
 56	      text: 'Ctrl + Alt + 2',
 57	    },
 58	  ];
 59	
