 61	    e.currentTarget.blur();
 62	    e.preventDefault();
 63	    rfb?.sendPasteCMD();
 64	    serialSocket?.onPaste();
 65	  };
 66	
 67	  const onDisconnect = () => {
 68	    rfb?.disconnect();
 69	    serialSocket?.destroy();
 70	  };
 71	
 72	  return (
 73	    <>
 74	      <Button
 75	        icon={
 76	          <>
 77	            <PasteIcon /> {t('Paste to console')}
 78	          </>
 79	        }
