 86	          setType(selection);
 87	          setIsOpenSelectType(false);
 88	        }}
 89	        toggle={SelectToggle({
 90	          className: 'access-consoles-selector',
 91	          id: 'pf-v5-c-console__type-selector',
 92	          isExpanded: isOpenSelectType,
 93	          onClick: () => setIsOpenSelectType((prevIsOpen) => !prevIsOpen),
 94	          selected: type,
 95	        })}
 96	        aria-label={t('Select console type')}
 97	        isOpen={isOpenSelectType}
 98	        onOpenChange={(open: boolean) => setIsOpenSelectType(open)}
 99	        placeholder={t('Select console type')}
100	        selected={type}
101	      >
102	        <SelectList>
103	          {Object.values(typeMap(isWindowsVM)).map((name: string) => {
104	            return (
105	              <SelectOption id={name} key={name} value={name}>
106	                {name}
107	              </SelectOption>
108	            );
109	          })}
110	        </SelectList>
111	      </Select>
112	      <Dropdown
113	        toggle={DropdownToggle({
114	          children: <>{t('Send key')}</>,
115	          className: 'access-consoles-selector',
116	          id: 'pf-v5-c-console__actions-vnc-toggle-id',
117	          isDisabled: !rfb,
118	          isExpanded: isOpenSendKey,
119	          onClick: () => setIsOpenSendKey((prevIsOpen) => !prevIsOpen),
120	        })}
121	        isOpen={isOpenSendKey}
122	        onOpenChange={(open: boolean) => setIsOpenSendKey(open)}
123	        onSelect={() => setIsOpenSendKey(false)}
124	      >
125	        <DropdownList>
126	          {customButtons?.map(({ onClick, text }) => (
127	            <DropdownItem key={text} onClick={onClick}>
128	              {text}
129	            </DropdownItem>
130	          ))}
131	        </DropdownList>
132	      </Dropdown>
133	      <Button
134	        className="vnc-actions-disconnect-button"
135	        isDisabled={status !== connected}
136	        onClick={onDisconnect}
137	        variant={ButtonVariant.secondary}
138	      >
139	        {t('Disconnect')}
140	      </Button>
141	    </>
142	  );
143	};
144	
145	AccessConsoles.displayName = 'AccessConsoles';

